inserted_products AS (
  INSERT INTO products (code, name, category_id, format_ml, sale_price, is_active)
  SELECT
    w.code,
    w.name,
    c.id,
    w.format_ml,
    w.sale_price,
    true
  FROM wine_data w
  JOIN categories c ON c.name = w.cepa
  WHERE NOT EXISTS (SELECT 1 FROM products p WHERE p.code = w.code)
  RETURNING id
)
-- Step 2: Create inventory records in bodega with stock=0
INSERT INTO inventory (product_id, location, quantity_ml, min_stock_ml)
SELECT id, 'bodega', 0, 0
FROM inserted_products
ON CONFLICT DO NOTHING;
